mapper.select:
SELECT *
FROM  yy_route_detail_places
WHERE
    route_id = #{routeId}
    and detail_id = #{detailId}
    and branch_no = #{branchNo}

SELECT r.*
, fav.favorite_flg
FROM yy_route r
JOIN ( SELECT route_id FROM yy_route_detail_places WHERE pass_place_id IN
#{id}
GROUP BY route_id HAVING COUNT(DISTINCT pass_place_id) = #{placeCount} ) t ON r.id = t.route_id
left outer join yy_user_favorite fav on r.id = fav.target_id and target_kbn = '03' and user_type = '01' and user_id = #{customerId}
ORDER BY r.id LIMIT #{offset}, #{pageSize}
